def detectCycle(self, head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            p = head
            while p is not slow:
                p = p.next
                slow = slow.next
            return p
    return None

def detectCycle_set(self, head):
    seen = set()
    cur = head
    while cur:
        if id(cur) in seen:
            return cur
        seen.add(id(cur))
        cur = cur.next
    return None
